from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Mock user database
users = {
    "user1": {
        "password": generate_password_hash("password123"),
        "mfa_enabled": True,
        "mfa_code": "123456"  # This should be securely stored and updated
    },
    "api_client": {
        "password": generate_password_hash("secure_api_key"),
        "mfa_enabled": False
    }
}

def verify_user(username, password):
    user = users.get(username)
    if user and check_password_hash(user['password'], password):
        return user
    return None

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')

    user = verify_user(username, password)
    if not user:
        return jsonify({"error": "Invalid credentials"}), 401

    session['user'] = username

    if user['mfa_enabled']:
        # Here you would typically send an OTP to the user's registered device
        # For simplicity, we assume the OTP is provided in the request
        otp = request.form.get('otp')
        if otp == user['mfa_code']:
            return jsonify({"message": "Logged in successfully with MFA"})
        else:
            return jsonify({"error": "Invalid OTP"}), 401

    return jsonify({"message": "Logged in successfully without MFA"})

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    username = request.form.get('username')
    password = request.form.get('password')

    user = verify_user(username, password)
    if not user or user['mfa_enabled']:
        return jsonify({"error": "Unauthorized"}), 403

    session['user'] = username
    return jsonify({"message": "API login successful"})

